import { writeOutput } from "./codegen";

const DOCS_URL = "https://learn.microsoft.com/en-us/graph/auth/auth-concepts";
const PLACEHOLDER_VALUE =
  "vm0placeholderOutlookMailToken0000000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Microsoft Graph API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:outlook-mail",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const outlookMailFirewall: FirewallConfig = {",
    '  name: "outlook-mail",',
    '  description: "Microsoft Graph API (Outlook Mail)",',
    "  placeholders: {",
    `    OUTLOOK_MAIL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://graph.microsoft.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.OUTLOOK_MAIL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "unrestricted",',
    '          description: "Allow all Microsoft Graph API endpoints",',
    '          rules: ["ANY /{path*}"],',
    "        },",
    "      ],",
    "    },",
    "  ],",
    "};",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Outlook Mail firewall config...");
  const ts = generateTypeScript();
  writeOutput("outlook-mail", ts, import.meta.dirname);
}
